import pytest

@pytest.fixture
def research_app():
    return inner.compile()   # compile without checkpointer for pure unit tests

def test_research_returns_ranked_docs(research_app):
    result = research_app.invoke({
        "topic": "quantum computing",
        "research_docs": [],
        "raw_results": [],
    })
    assert len(result["research_docs"]) > 0
    assert len(result["research_docs"]) <= 5   # rank capped at top 5
    # raw_results should not leak out
    assert "raw_results" not in result or result["raw_results"] == []

def test_research_empty_results_handled(research_app):
    # Mock web_search to return empty
    result = research_app.invoke({"topic": "zzzunknownxyz", "research_docs": [], "raw_results": []})
    # Should not crash — returns empty list
    assert isinstance(result["research_docs"], list)

# Correct: subgraph returns only new docs (delta), outer reducer appends them
class ResearchState(TypedDict):
    topic: str
    research_docs: Annotated[list[str], operator.add]  # outer uses add reducer

def rank(state: ResearchState) -> dict:
    # Return ONLY the top-5 new docs — do NOT return the full accumulated list
    new_docs = sorted(state["raw_results"], key=lambda d: score(d))[:5]
    return {"research_docs": new_docs}   # outer.add appends these 5 to its existing list

# Wrong: returning the full list when outer uses add reducer causes duplication
def rank_wrong(state: ResearchState) -> dict:
    return {"research_docs": state["research_docs"] + sorted(state["raw_results"])[:5]}
    # outer.add would append the already-accumulated list again — duplicates!
